mapper.select:
/* wms-inventory-asrtrenewal-sql-oracle.xml - selectAsrtRenewalItemPrintList */ WITH T_INVN AS ( SELECT A.CTKEY , A.OWKEY , A.ICKEY , SUM(A.AVQTY) AS AVQTY , SUM(A.NAVQTY) AS NAVQTY , A.AVZNYN FROM ( SELECT IVLC.CTKEY , IVLC.OWKEY , IVLC.ICKEY , CASE ZN.ZNTYPECD WHEN '10' THEN IVLC.TOTQTY ELSE 0 END AS AVQTY , CASE ZN.ZNTYPECD WHEN '10' THEN 0 ELSE IVLC.TOTQTY END AS NAVQTY , CASE ZN.ZNTYPECD WHEN '10' THEN 'Y' ELSE 'N' END AS AVZNYN FROM TWORK_INFO_IVATXLC IVLC INNER JOIN TWORK_INFO_IVAT IV ON IV.CTKEY = IVLC.CTKEY AND IV.OWKEY = IVLC.OWKEY AND IV.ICKEY = IVLC.ICKEY AND IV.IVATKEY = IVLC.IVATKEY INNER JOIN TWORK_MST_LC LC ON LC.CTKEY = IVLC.CTKEY AND LC.LCKEY = IVLC.LCKEY INNER JOIN TWORK_MST_ZN ZN ON ZN.CTKEY = IVLC.CTKEY AND ZN.ZNKEY = LC.ZNKEY INNER JOIN TWORK_MST_AR AR ON AR.CTKEY = IVLC.CTKEY AND AR.ZNKEY = LC.ZNKEY AND AR.ARKEY = LC.ARKEY WHERE IVLC.TOTQTY > 0 ) A GROUP BY A.CTKEY , A.OWKEY , A.ICKEY , A.AVZNYN )
SELECT '0' AS CHK , ASTR.CTKEY /* 센터코드 */ , ASTR.OWKEY /* 화주코드 */ , ASTR.BFCHGICKEY /* 변경전 상품코드 */ , BFIC.ICNM AS BFCHGICNM /* 변경전 상품명 */ , ASTR.AFCHGICKEY /* 변경후 상품코드 */ , AFIC.ICNM AS AFCHGICNM /* 변경후 상품명 */ , ICBC.BARCODE /* 상품바코드 */ , ASTR.IVCNVRSNYN /* 재고전환 여부 */ , ASTR.LBLPRYN /* 라벨출력 여부 */ , COALESCE(AVINVN.AVQTY, 0) AS AVQTY /* 가용재고 */ , COALESCE(NAVINVN.NAVQTY, 0) AS NAVQTY /* 불용재고 */ , 0 AS PRINTQTY , AFIC.LCKEY , LC.RACKNO , LC.ROWNO , LC.TIERNO , ASTR.INSERTDATE /* 등록일자 */ , ASTR.INSERTURKEY /* 등록자 */ , ASTR.UPDATEDATE /* 수정일자 */ , ASTR.UPDATEURKEY /* 수정자 */ FROM TWORK_INFO_ASRT_RENEW ASTR INNER JOIN TWORK_MST_CT CT ON CT.CTKEY = ASTR.CTKEY INNER JOIN TWORK_MST_OW OW ON OW.OWKEY = ASTR.OWKEY INNER JOIN TWORK_MST_IC BFIC ON BFIC.CTKEY = ASTR.CTKEY AND BFIC.OWKEY = ASTR.OWKEY AND BFIC.ICKEY = ASTR.BFCHGICKEY INNER JOIN TWORK_MST_IC AFIC ON AFIC.CTKEY = ASTR.CTKEY AND AFIC.OWKEY = ASTR.OWKEY AND AFIC.ICKEY = ASTR.AFCHGICKEY LEFT JOIN TWORK_MST_ICBARCODE ICBC ON ICBC.CTKEY = ASTR.CTKEY AND ICBC.OWKEY = ASTR.OWKEY AND ICBC.ICKEY = ASTR.AFCHGICKEY AND ICBC.UOM = 'EA' AND ICBC.USEYN = 'Y' LEFT JOIN T_INVN AVINVN ON AVINVN.CTKEY = ASTR.CTKEY AND AVINVN.OWKEY = ASTR.OWKEY AND AVINVN.ICKEY = ASTR.AFCHGICKEY AND AVINVN.AVZNYN = 'Y' LEFT JOIN T_INVN NAVINVN ON NAVINVN.CTKEY = ASTR.CTKEY AND NAVINVN.OWKEY = ASTR.OWKEY AND NAVINVN.ICKEY = ASTR.AFCHGICKEY AND NAVINVN.AVZNYN = 'N' LEFT JOIN TWORK_MST_LC LC ON LC.CTKEY = AFIC.CTKEY AND LC.LCKEY = AFIC.LCKEY
AND ASTR.CTKEY || ASTR.OWKEY || ASTR.BFCHGICKEY || ASTR.AFCHGICKEY IN
#{info.ctkey} || #{info.owkey} || #{info.bfchgickey} || #{info.afchgickey}

mapper.update:
/* wms-inventory-asrtrenewal-sql-oracle.xml - saveAsrtRenewalItemPrintYn */
UPDATE TWORK_INFO_ASRT_RENEW
   SET UPDATEDATE  = #{sysdate}
	 , UPDATEURKEY = #{surkey}
     , LBLPRYN = 'Y'
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND BFCHGICKEY = #{bfchgickey}
   AND AFCHGICKEY = #{afchgickey}

