/* wms-inventory-asrtrenewal-sql-oracle.xml - selectTworkInfoIvatCount */
SELECT COUNT(1)
  FROM TWORK_INFO_IVAT
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND ICKEY = #{ickey}



		AND EXPDATE = #{expdate}


		AND EXPDATE IS NULL

mapper.insert:
/* wms-inventory-asrtrenewal-sql-oracle.xml - insertTworkInfoIvat */
INSERT INTO TWORK_INFO_IVAT
SELECT CTKEY
	 , OWKEY
	 , #{ivatkey}
	 , #{ickey}
	 , TCDCDIVCD
	 , PRDCTDATE
	 , EXPDATE
	 , EXPIMMTDATE
	 , OBIMPSDATE
	 , ICTMPRDIVCD
	 , IVATSTATUSCD
	 , IBCNFRMDATE
	 , #{sysdate}
	 , #{surkey}
	 , #{sysdate}
	 , #{surkey}
  FROM TWORK_INFO_IVAT
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND IVATKEY = #{dtivatkey}

mapper.select:
/* wms-inventory-asrtrenewal-sql-oracle.xml - selectTworkInfoAsrtRenewConvert */
SELECT CASE WHEN COUNT(1) = 0 THEN 'Y'
            ELSE 'N'
       END AS  COMPLETEYN          /* 가용재고 전환 여부 */
  FROM TWORK_INFO_IVATXLC
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND ICKEY = #{bfchgickey}
   AND TOTQTY > 0

mapper.update:
/* wms-inventory-asrtrenewal-sql-oracle.xml - updateTworkInfoAsrtRenewConvert */
UPDATE TWORK_INFO_ASRT_RENEW
   SET UPDATEDATE  = #{sysdate}
	 , UPDATEURKEY = #{surkey}
	 , IVCNVRSNYN = #{completeyn}
WHERE CTKEY = #{ctkey}
  AND OWKEY = #{owkey}
  AND BFCHGICKEY = #{bfchgickey}
  AND AFCHGICKEY = #{afchgickey}
